from haystack import Pipeline
from haystack.components.builders import CustomComponent
from vex_sdk import VexClient

class VexGuard(CustomComponent):
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    def run(self, query: str, retrieved_docs: list, generated_text: str):
        result = self.vex.check({
            "prompt": query,
            "context": [doc.content for doc in retrieved_docs],
            "output": generated_text,
            "rules": ["no_unsubstantiated_claims", "accurate_pricing", "correct_policy"]
        })
        if not result.valid:
            return {"output": "Compliance check failed. Please refine your query.", "is_valid": False}
        return {"output": generated_text, "is_valid": True}

# Usage in pipeline
vex_guard = VexGuard()
pipeline.add_component("vex_guard", vex_guard)
pipeline.connect("generator", "vex_guard.generated_text")
pipeline.connect("retriever", "vex_guard.retrieved_docs")
pipeline.connect("vex_guard", "output")

from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever
from vex_sdk import VexClient

class CompliantRetriever(InMemoryEmbeddingRetriever):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.vex = VexClient(api_key="your-vex-key")

    def run(self, query: str, **kwargs):
        docs = super().run(query=query, **kwargs)["documents"]
        relevance_scores = self.vex.score_retrieval(query, [d.content for d in docs])
        filtered_docs = [docs[i] for i, score in enumerate(relevance_scores) if score > 0.8]
        return {"documents": filtered_docs}

