import re
from haystack.components.builders import CustomComponent
from vex_sdk import VexClient

class PricingValidator(CustomComponent):
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")
        self.price_pattern = r'\$?(\d+(?:\.\d{2})?)'

    def run(self, text: str, product_id: str):
        prices = re.findall(self.price_pattern, text)
        for price_str in prices:
            price = float(price_str)
            canonical_price = self.vex.get_product_price(product_id)
            if abs(price - canonical_price) > 0.01:
                return {"approved": False, "error": f"Price mismatch: ${price} vs ${canonical_price}"}
        return {"approved": True}

pipeline.add_component("price_validator", PricingValidator())
pipeline.connect("generator", "price_validator.text")
pipeline.connect("metadata", "price_validator.product_id")
